import { TypeQuizQuestion } from "./quiz-types";
export const newQType5: TypeQuizQuestion[] = [
  // ── DIFFICULTY 1 (20 questions) ──
  { id: 851, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Real-Life Scenarios", question: "A Type 5 arrives at a social gathering. Their first instinct is:", options: [{ letter: "A", text: "Work the room and meet everyone" }, { letter: "B", text: "Find a quiet observation point where they can watch without being drawn into small talk" }, { letter: "C", text: "Offer to help the host" }, { letter: "D", text: "Take charge of the music or entertainment" }], answer: "B", explanation: "Fives automatically seek a position where they can observe without being demanded upon. Social settings drain their energy reserves, so they strategically minimize engagement while maximizing informational intake." },
  { id: 852, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Real-Life Scenarios", question: "A Type 5's phone rings unexpectedly. Their typical reaction is:", options: [{ letter: "A", text: "Answer immediately with enthusiasm" }, { letter: "B", text: "Let it ring, check who it is, and decide later whether to return the call" }, { letter: "C", text: "Panic about what bad news it might be" }, { letter: "D", text: "Answer and chat for an hour" }], answer: "B", explanation: "Unexpected phone calls feel like intrusions to Fives, unplanned demands on their energy and attention. They need to assess the situation before committing resources. Screening calls preserves their sense of control over their own time." },
  { id: 853, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Emotional Reactions", question: "When a Type 5 feels overwhelmed by emotion, they typically:", options: [{ letter: "A", text: "Express it dramatically to everyone nearby" }, { letter: "B", text: "Withdraw to process it alone, often through thinking rather than feeling" }, { letter: "C", text: "Seek physical comfort from others" }, { letter: "D", text: "Channel it into physical activity" }], answer: "B", explanation: "Fives retreat from emotion to understand it. They convert feeling into thinking, analyzing the emotion rather than experiencing it. This creates a time delay: they may understand what they felt days later, after processing it intellectually." },
  { id: 854, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Emotional Reactions", question: "When someone unexpectedly hugs a Type 5, they most likely:", options: [{ letter: "A", text: "Melt into the embrace" }, { letter: "B", text: "Stiffen slightly, endure it politely, and feel their personal space has been invaded" }, { letter: "C", text: "Hug back with enthusiasm" }, { letter: "D", text: "Push the person away immediately" }], answer: "B", explanation: "Physical contact without consent feels like an energy withdrawal to Fives. They experience it as boundary violation, not because they dislike the person, but because unrequested intimacy depletes their carefully managed reserves." },
  { id: 855, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Type in Pop Culture", question: "Which fictional character best exemplifies Type 5 traits of intellectual withdrawal and observation?", options: [{ letter: "A", text: "Tony Stark (before character development)" }, { letter: "B", text: "Sherlock Holmes" }, { letter: "C", text: "Ted Lasso" }, { letter: "D", text: "Captain America" }], answer: "B", explanation: "Sherlock Holmes is the archetypal Five: brilliant observation from a position of emotional detachment, minimal social needs, vast specialized knowledge, a mind palace of accumulated information, and a fundamental discomfort with emotional demands." },
  { id: 856, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Type in Pop Culture", question: "In The Big Bang Theory, which character most displays Type 5 patterns of intellectual withdrawal and social minimalism?", options: [{ letter: "A", text: "Howard Wolowitz" }, { letter: "B", text: "Sheldon Cooper" }, { letter: "C", text: "Penny" }, { letter: "D", text: "Raj Koothrappali" }], answer: "B", explanation: "Sheldon exemplifies (and caricatures) Five traits: encyclopedic knowledge, rigid boundaries, discomfort with emotion and physical contact, the need for predictable routines that minimize surprise demands, and intellectual superiority as a defense." },
  { id: 857, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Quick Identification", question: "Which phrase is most characteristic of a Type 5?", options: [{ letter: "A", text: "Let me help you with that" }, { letter: "B", text: "I need some time alone to think about this" }, { letter: "C", text: "Let's just go for it!" }, { letter: "D", text: "How is everyone feeling about this?" }], answer: "B", explanation: "This request for solitary processing time is the Five's signature. They need to withdraw to their mental space before engaging, not because they're slow, but because their processing is internal and requires privacy." },
  { id: 858, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Quick Identification", question: "Which behavior most suggests someone is a Type 5?", options: [{ letter: "A", text: "Having a wide social circle and attending every event" }, { letter: "B", text: "Developing deep expertise in niche subjects that few others know about" }, { letter: "C", text: "Volunteering for every committee" }, { letter: "D", text: "Being the first to raise their hand in meetings" }], answer: "B", explanation: "Fives collect knowledge the way others collect possessions. They develop deep expertise in specialized areas, often obscure or niche, because mastery provides the sense of competence that makes the world feel less threatening." },
  { id: 859, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Common Phrases", question: "Which internal monologue is most typical for a Type 5?", options: [{ letter: "A", text: "What does this person need from me?" }, { letter: "B", text: "Do I have enough knowledge and energy to handle this situation?" }, { letter: "C", text: "Am I being admired?" }, { letter: "D", text: "Is this fair?" }], answer: "B", explanation: "The Five's internal calculus constantly evaluates resource levels: 'Do I know enough? Do I have enough energy? Can I handle what's being asked?' They monitor their reserves like a pilot monitors fuel, because running out feels catastrophic." },
  { id: 860, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Common Phrases", question: "A Five is asked 'How was your day?' They typically respond:", options: [{ letter: "A", text: "With a detailed emotional narrative" }, { letter: "B", text: "With a brief, factual summary that omits emotional content" }, { letter: "C", text: "By turning the question back: 'How was YOUR day?'" }, { letter: "D", text: "With an enthusiastic play-by-play" }], answer: "B", explanation: "Fives edit emotional content from their communications. They share facts and events but filter out feelings, not because they don't have them, but because sharing emotions feels like giving away something precious and vulnerable." },
  { id: 861, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 11, track2Day: 61, category: "Childhood Patterns", question: "What childhood experience is most formative for Type 5s?", options: [{ letter: "A", text: "Being the center of attention" }, { letter: "B", text: "Feeling that their environment was intrusive, overwhelming, or that they had to protect their inner world from being invaded" }, { letter: "C", text: "Being praised for emotional expression" }, { letter: "D", text: "Having everything provided without effort" }], answer: "B", explanation: "Fives typically grew up in environments that felt intrusive, a demanding parent, chaotic household, or lack of privacy. They learned to survive by retreating inward, building a rich mental world that no one could access or take away." },
  { id: 862, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 12, track2Day: 62, category: "Childhood Patterns", question: "As children, Type 5s were often described as:", options: [{ letter: "A", text: "The most social kid in class" }, { letter: "B", text: "An 'old soul', quiet, observant, self-contained, and oddly self-sufficient for their age" }, { letter: "C", text: "The class clown" }, { letter: "D", text: "The most physically active kid" }], answer: "B", explanation: "Young Fives often struck adults as precociously independent and unusually self-contained. They didn't demand attention; they observed. They entertained themselves with books, experiments, or solitary projects, miniature scholars." },
  { id: 863, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 13, track2Day: 63, category: "Communication Style", question: "How does a Type 5 typically express disagreement?", options: [{ letter: "A", text: "With emotional intensity" }, { letter: "B", text: "With precise, logical arguments delivered in a detached, almost clinical tone" }, { letter: "C", text: "By raising their voice" }, { letter: "D", text: "By seeking allies to support their position" }], answer: "B", explanation: "Fives disagree with data, not drama. They present counterarguments with the emotional detachment of a scientist presenting findings. This clinical delivery can be frustrating for people who want emotional engagement in disagreements." },
  { id: 864, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 14, track2Day: 64, category: "Communication Style", question: "A Five's ideal meeting format is:", options: [{ letter: "A", text: "Brainstorming with high energy" }, { letter: "B", text: "A pre-circulated agenda with time limits, allowing them to prepare their contributions in advance" }, { letter: "C", text: "Free-flowing emotional check-ins" }, { letter: "D", text: "Spontaneous and unstructured" }], answer: "B", explanation: "Fives want meetings that respect their preparation style. Surprise demands for on-the-spot ideas feel like ambushes. Pre-circulated agendas allow them to prepare their contributions, which are typically thorough and well-reasoned." },
  { id: 865, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 15, track2Day: 65, category: "Real-Life Scenarios", question: "A Five's partner says 'We need to talk about our relationship.' The Five's internal reaction is:", options: [{ letter: "A", text: "Excitement at the chance to connect" }, { letter: "B", text: "A sense of dread, they feel unprepared for an emotional demand they didn't see coming" }, { letter: "C", text: "Eager curiosity" }, { letter: "D", text: "Anger at being challenged" }], answer: "B", explanation: "These words trigger the Five's core fear: an unplanned emotional demand they can't prepare for. They need time to think, not feel on demand. The ambush format of 'we need to talk' is the Five's relationship nightmare." },
  { id: 866, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 16, track2Day: 66, category: "Emotional Reactions", question: "When a Five is genuinely excited about something, they:", options: [{ letter: "A", text: "Jump up and down visibly" }, { letter: "B", text: "Become animated and talkative, often surprising others who assumed the Five was always reserved" }, { letter: "C", text: "Keep it entirely to themselves" }, { letter: "D", text: "Express it only through emojis" }], answer: "B", explanation: "Fives light up when discussing their passions. The reserved exterior drops, and they become surprisingly animated and verbose. This animation startles people who only know the Five's default mode of quiet observation." },
  { id: 867, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 17, track2Day: 67, category: "Quick Identification", question: "Which living space most suggests a Five?", options: [{ letter: "A", text: "Open-plan with no doors" }, { letter: "B", text: "A personal space filled with books, screens, or specialized equipment, with a definite 'do not disturb' vibe" }, { letter: "C", text: "Lavishly decorated for entertaining" }, { letter: "D", text: "Minimalist with nothing personal" }], answer: "B", explanation: "The Five's living space is their sanctuary. It's filled with the tools of their knowledge pursuit, books, computers, instruments, and designed for privacy. The space says: 'This is my world. Enter by invitation only.'" },
  { id: 868, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 18, track2Day: 68, category: "Common Phrases", question: "Which phrase reveals the Five's core relationship with energy?", options: [{ letter: "A", text: "The more people the better!" }, { letter: "B", text: "I need to recharge, today was a lot" }, { letter: "C", text: "I'm bored, let's do something" }, { letter: "D", text: "I feel so energized by that interaction" }], answer: "B", explanation: "Fives experience social and emotional interactions as energy expenditures. They have a felt sense of finite resources that must be carefully managed. 'Recharging' in solitude isn't a preference, it's a survival necessity." },
  { id: 869, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 19, track2Day: 69, category: "Childhood Patterns", question: "Five children typically found comfort in:", options: [{ letter: "A", text: "Group activities and team sports" }, { letter: "B", text: "Solitary intellectual pursuits, books, computers, nature observation, or building things alone" }, { letter: "C", text: "Performing for audiences" }, { letter: "D", text: "Helping their parents with household tasks" }], answer: "B", explanation: "Young Fives found their safe space in the mind. Books, experiments, collections, and solitary exploration became the world they could control and understand, unlike the unpredictable world of people and emotions." },
  { id: 870, type: 5, difficulty: 1 as 1|2|3|4|5, track1Day: 20, track2Day: 70, category: "Communication Style", question: "When a Five sends a text message, it typically:", options: [{ letter: "A", text: "Contains lots of emojis and exclamation marks" }, { letter: "B", text: "Is concise, informational, and may take longer to compose than expected because they're crafting precise wording" }, { letter: "C", text: "Is stream-of-consciousness and emotional" }, { letter: "D", text: "Comes immediately without thought" }], answer: "B", explanation: "Fives treat text communication like a written document: precise, edited, minimal. They may take 20 minutes to craft a three-sentence text because every word must be accurate. Efficiency in communication reflects their conservation of resources." },
  // ── DIFFICULTY 2 (20 questions) ──
  { id: 871, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 21, track2Day: 71, category: "Relationship Dynamics", question: "In romantic relationships, Type 5s are most at risk of:", options: [{ letter: "A", text: "Being too emotionally demanding" }, { letter: "B", text: "Withholding emotionally, giving their partner access to their mind but not their heart, creating intimacy starvation" }, { letter: "C", text: "Being too jealous and possessive" }, { letter: "D", text: "Rushing into commitment" }], answer: "B", explanation: "Fives share ideas but guard feelings. Partners often feel they have intellectual access but emotional exclusion, like being invited into the library but locked out of the bedroom. The Five may not realize they're withholding because to them, sharing knowledge IS intimacy." },
  { id: 872, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 22, track2Day: 72, category: "Relationship Dynamics", question: "Why does the 5-2 pairing create a 'pursuer-distancer' dynamic?", options: [{ letter: "A", text: "Random chance" }, { letter: "B", text: "The Two pursues emotional connection while the Five retreats, the Two's need for intimacy triggers the Five's need for space, creating a self-reinforcing chase pattern" }, { letter: "C", text: "They share the same communication style" }, { letter: "D", text: "They don't create this dynamic" }], answer: "B", explanation: "It's a classic polarity: the more the Two reaches for connection, the more the Five withdraws. The more the Five withdraws, the more desperately the Two reaches. Each partner's coping strategy triggers the other's core fear." },
  { id: 873, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 23, track2Day: 73, category: "Defense Mechanisms", question: "What is the primary defense mechanism of Type 5?", options: [{ letter: "A", text: "Repression" }, { letter: "B", text: "Isolation of affect, separating thoughts from feelings so they can analyze experiences without being overwhelmed by emotion" }, { letter: "C", text: "Denial" }, { letter: "D", text: "Reaction formation" }], answer: "B", explanation: "Isolation of affect is the Five's signature defense: they split thought from feeling, keeping the intellectual content while stripping the emotional charge. This allows them to discuss painful topics with eerie calm, the feelings exist, but in a separate, locked room." },
  { id: 874, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 24, track2Day: 74, category: "Defense Mechanisms", question: "The Five's 'avarice' passion doesn't mean greed for money. It means:", options: [{ letter: "A", text: "Collecting expensive things" }, { letter: "B", text: "A compulsive hoarding of internal resources, time, energy, knowledge, privacy, driven by the belief that they don't have enough to meet the world's demands" }, { letter: "C", text: "Being cheap" }, { letter: "D", text: "Wanting power" }], answer: "B", explanation: "Five's avarice is about conservation: they hoard time, energy, and privacy because they believe their reserves are dangerously limited. It's not greed, it's the desperate economy of someone who feels they'll run out if they give too freely." },
  { id: 875, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 25, track2Day: 75, category: "Conflict Style", question: "How do Type 5s typically handle conflict?", options: [{ letter: "A", text: "With passionate emotional expression" }, { letter: "B", text: "By withdrawing to analyze the situation, then returning with a carefully constructed position, or by simply disappearing from the conflict entirely" }, { letter: "C", text: "By escalating aggressively" }, { letter: "D", text: "By people-pleasing to make it go away" }], answer: "B", explanation: "Fives need processing time before engaging in conflict. They withdraw, analyze, prepare, then re-emerge with a precise position. If the conflict is emotional rather than logical, they may simply exit, emotional confrontation without preparation is their worst scenario." },
  { id: 876, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 26, track2Day: 76, category: "Conflict Style", question: "What does a Five's anger look like when it finally surfaces?", options: [{ letter: "A", text: "Hot and explosive" }, { letter: "B", text: "Cold, precise, and devastating, they deploy accumulated observations as weaponized data, dissecting the other person with clinical accuracy" }, { letter: "C", text: "Tearful and emotional" }, { letter: "D", text: "Physical aggression" }], answer: "B", explanation: "Five anger is cold fury: they've been observing and cataloging for months. When they finally express anger, it's surgical, they know exactly where your weaknesses are and can dismantle your position with terrifying precision." },
  { id: 877, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 27, track2Day: 77, category: "Shadow Work", question: "What is the Five's deepest fear?", options: [{ letter: "A", text: "Being unimportant" }, { letter: "B", text: "Being helpless, incapable, and overwhelmed, unable to cope with the world's demands because they lack sufficient resources or competence" }, { letter: "C", text: "Being unloved" }, { letter: "D", text: "Being boring" }], answer: "B", explanation: "The Five's core fear is incompetence in the face of reality's demands. They prepare, study, and withdraw to ensure they're never caught unprepared. Knowledge is their shield against the overwhelming world, without it, they're exposed." },
  { id: 878, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 28, track2Day: 78, category: "Shadow Work", question: "The Five's 'knowledge hoarding' pattern serves to:", options: [{ letter: "A", text: "Make them smarter" }, { letter: "B", text: "Create a sense of competence and control that substitutes for actual engagement with life, they prepare endlessly without ever feeling 'ready' to act" }, { letter: "C", text: "Help others" }, { letter: "D", text: "Build their career" }], answer: "B", explanation: "Fives can spend years preparing to engage and never actually engage. The preparation becomes an end in itself, a fortress of knowledge that promises safety but actually becomes a prison. They know everything about life but aren't living it." },
  { id: 879, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 29, track2Day: 79, category: "Parenting Style", question: "Type 5 parents are most likely to:", options: [{ letter: "A", text: "Be physically affectionate and emotionally expressive" }, { letter: "B", text: "Teach through knowledge-sharing and intellectual engagement while struggling with the emotional intimacy and physical affection their children need" }, { letter: "C", text: "Be extremely strict disciplinarians" }, { letter: "D", text: "Over-schedule their children's activities" }], answer: "B", explanation: "Five parents excel at intellectual nurturing, explaining the world, encouraging curiosity, and respecting their children's independence. Their challenge is the messy, emotional, physical demand of parenting: hugs, bedtime tears, and 'just sit with me.'" },
  { id: 880, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 30, track2Day: 80, category: "Attachment Style", question: "Which attachment style is most common among Type 5s?", options: [{ letter: "A", text: "Anxious-preoccupied" }, { letter: "B", text: "Dismissive-avoidant, they've learned to minimize attachment needs by becoming self-sufficient, treating emotional independence as survival" }, { letter: "C", text: "Secure" }, { letter: "D", text: "Anxious-ambivalent" }], answer: "B", explanation: "Fives are the most consistently dismissive-avoidant type. They learned early that needing others was dangerous, so they built an internal world that doesn't require external input. Their self-sufficiency is a survival strategy, not a character trait." },
  { id: 881, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 31, track2Day: 81, category: "Somatic Patterns", question: "Where do Type 5s most commonly experience stress in their body?", options: [{ letter: "A", text: "Their heart center" }, { letter: "B", text: "Their head, headaches, eye strain, and tension in the skull and neck from constant mental activity and physical under-engagement" }, { letter: "C", text: "Their stomach" }, { letter: "D", text: "Their extremities" }], answer: "B", explanation: "As a Head center type who lives predominantly in their mind, Fives' stress concentrates above the shoulders: headaches, eye strain, jaw clenching, and neck tension. Their body is under-inhabited, all the energy flows upward into thought." },
  { id: 882, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 32, track2Day: 82, category: "Somatic Patterns", question: "Fives often describe feeling 'drained' after social interaction because:", options: [{ letter: "A", text: "They're physically weak" }, { letter: "B", text: "They experience emotional and social demands as literal energy expenditures, their nervous system treats interpersonal contact as a cost to be managed" }, { letter: "C", text: "They're pretending" }, { letter: "D", text: "They don't eat enough" }], answer: "B", explanation: "The Five's experience of depletion is somatic and real, not imagined. Their nervous system genuinely treats social interaction as a drain on limited resources. This isn't introversion, it's a survival-level conservation strategy operating below conscious choice." },
  { id: 883, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 33, track2Day: 83, category: "Coping Under Stress", question: "When stressed, Type 5s move toward which type's behaviors?", options: [{ letter: "A", text: "Type 2, becoming warm and people-pleasing" }, { letter: "B", text: "Type 7, becoming scattered, hyperactive, and seeking stimulation to escape the intensity of their inner constriction" }, { letter: "C", text: "Type 4, becoming emotional and dramatic" }, { letter: "D", text: "Type 1, becoming rigid and critical" }], answer: "B", explanation: "Under stress, Fives disintegrate to Seven: the focused observer becomes scattered and restless. They may binge-consume content, hop between projects, or seek stimulation as an escape from the constriction of their withdrawal." },
  { id: 884, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 34, track2Day: 84, category: "Coping Under Stress", question: "What does healthy growth look like for a Type 5?", options: [{ letter: "A", text: "Accumulating more knowledge" }, { letter: "B", text: "Moving toward Type 8 qualities: taking decisive action, engaging physically with the world, and expressing their power rather than observing from the sidelines" }, { letter: "C", text: "Becoming more isolated" }, { letter: "D", text: "Becoming more analytical" }], answer: "B", explanation: "In growth, Fives integrate to Eight: the detached observer becomes a powerful doer. They step out of the observation tower, engage physically and emotionally, take up space, and discover that acting in the world generates energy rather than depleting it." },
  { id: 885, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 35, track2Day: 85, category: "Workplace Archetypes", question: "Which workplace role does a Type 5 most naturally gravitate toward?", options: [{ letter: "A", text: "Team cheerleader and motivator" }, { letter: "B", text: "The deep technical expert or specialist, the person with irreplaceable domain knowledge" }, { letter: "C", text: "The social coordinator" }, { letter: "D", text: "The public-facing spokesperson" }], answer: "B", explanation: "Fives gravitate toward expert roles where deep knowledge is valued over social skills. They become the indispensable specialist, the person everyone turns to for answers. Their competence becomes their contribution and their protection." },
  { id: 886, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 36, track2Day: 86, category: "Workplace Archetypes", question: "A Five's biggest workplace blind spot is:", options: [{ letter: "A", text: "Lack of knowledge" }, { letter: "B", text: "Under-communicating, they know the answer but don't share it proactively, assuming others should figure it out themselves" }, { letter: "C", text: "Being too chatty in meetings" }, { letter: "D", text: "Oversharing personal information" }], answer: "B", explanation: "Fives hoard information unintentionally. They assume others have the same knowledge or should acquire it independently. They don't realize that their failure to share what they know creates bottlenecks, confusion, and resentment on their teams." },
  { id: 887, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 37, track2Day: 87, category: "Relationship Dynamics", question: "What makes Type 5s excellent partners when they're healthy?", options: [{ letter: "A", text: "Their social networking" }, { letter: "B", text: "Their deep listening, lack of drama, genuine respect for their partner's autonomy, and the profound trust embedded in letting someone into their carefully guarded inner world" }, { letter: "C", text: "Their emotional expressiveness" }, { letter: "D", text: "Their spontaneity" }], answer: "B", explanation: "When a Five lets you in, it means something extraordinary, they've deemed you worth their most precious resource. Healthy Fives offer rare gifts: genuine autonomy-respect, deep listening without agenda, and a steady presence unburdened by drama." },
  { id: 888, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 38, track2Day: 88, category: "Defense Mechanisms", question: "The Five's 'compartmentalization' pattern means:", options: [{ letter: "A", text: "They're organized" }, { letter: "B", text: "They keep different areas of life, work, relationships, inner world, in separate boxes that don't touch, preventing any one area from contaminating another" }, { letter: "C", text: "They have multiple hobbies" }, { letter: "D", text: "They're good at multitasking" }], answer: "B", explanation: "Fives manage complexity by isolating domains. Work doesn't touch relationships. Relationships don't touch family. This prevents overwhelming cross-contamination but also prevents integration, they can be a different person in each compartment." },
  { id: 889, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 39, track2Day: 89, category: "Shadow Work", question: "The Five's 'observer position' creates which existential problem?", options: [{ letter: "A", text: "They see too much" }, { letter: "B", text: "They experience life as spectators rather than participants, understanding everything but engaging with nothing, like watching their own life through glass" }, { letter: "C", text: "They become physically ill" }, { letter: "D", text: "They can't concentrate" }], answer: "B", explanation: "The Five's observation tower becomes a prison. They understand life brilliantly but don't live it. The gap between knowing and experiencing is the Five's fundamental existential crisis, all of life's beauty analyzed but none of it felt." },
  { id: 890, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 40, track2Day: 90, category: "Childhood Patterns", question: "The Five child's strategy of 'becoming invisible' served to:", options: [{ letter: "A", text: "Get attention" }, { letter: "B", text: "Reduce the demands placed on them, if no one noticed them, no one could drain their resources or invade their space" }, { letter: "C", text: "Make friends" }, { letter: "D", text: "Impress their parents" }], answer: "B", explanation: "Young Fives learned that visibility meant demands. Being noticed meant being asked for things they didn't have to give. Invisibility was a survival strategy: if no one sees me, no one can need me, and my limited resources remain intact." },
  // ── DIFFICULTY 3 (20 questions) ──
  { id: 891, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Spiritual Traditions", question: "In contemplative traditions, the Five's growth path involves:", options: [{ letter: "A", text: "More study and analysis" }, { letter: "B", text: "Embodiment practices, getting out of their head and into their body, discovering that direct experience provides a kind of knowledge that analysis cannot" }, { letter: "C", text: "Intellectual debate" }, { letter: "D", text: "Solitary retreat" }], answer: "B", explanation: "Fives overvalue mental knowing. Their spiritual path requires body-based practices: martial arts, embodied meditation, physical labor. They must discover that the body knows things the mind can't access, and that being IS knowing." },
  { id: 892, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Spiritual Traditions", question: "The Buddhist concept of 'beginner's mind' challenges the Five because:", options: [{ letter: "A", text: "They love beginner's mind" }, { letter: "B", text: "Their identity is built on expertise, the idea of deliberately not-knowing feels like giving up their only source of safety and competence" }, { letter: "C", text: "They're already beginners" }, { letter: "D", text: "They don't practice Buddhism" }], answer: "B", explanation: "Beginner's mind asks Fives to release their greatest possession: accumulated knowledge. It requires the terrifying surrender of expertise. For a Five, 'I don't know' isn't intellectual humility, it feels like standing naked in a storm." },
  { id: 893, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Enneagram x MBTI", question: "How does a Type 5 INTJ differ from a Type 5 INTP?", options: [{ letter: "A", text: "They're identical" }, { letter: "B", text: "The INTJ Five organizes knowledge into strategic systems and acts on conclusions; the INTP Five explores knowledge for its own sake and resists premature conclusions" }, { letter: "C", text: "Only INTPs can be Fives" }, { letter: "D", text: "INTJs are more emotional" }], answer: "B", explanation: "Same core type, different cognitive strategies. INTJ Fives build mental models and execute; INTP Fives collect information and refine theories endlessly. The INTJ Five is more likely to actually deploy their knowledge; the INTP Five may never feel 'ready.'" },
  { id: 894, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Enneagram x MBTI", question: "A Type 5 ENFJ is a rare combination that creates:", options: [{ letter: "A", text: "An impossible type" }, { letter: "B", text: "A deeply knowledgeable person who channels Five's depth through the ENFJ's desire to teach and connect, they become the professor, therapist, or mentor who uses their expertise in service of others' growth" }, { letter: "C", text: "A typical extrovert" }, { letter: "D", text: "A person with no contradictions" }], answer: "B", explanation: "5-ENFJ is unusual but powerful: the Five's depth married to the ENFJ's interpersonal mission creates an expert communicator, someone who's gone deep enough to have rare knowledge and feels compelled to share it for others' benefit." },
  { id: 895, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Instinct x Wing Combos", question: "How does a Social Five (SO5) differ from the stereotypical Five?", options: [{ letter: "A", text: "They're identical" }, { letter: "B", text: "SO5s are the counter-type, they seek knowledge through group affiliation, becoming the expert within a community or intellectual circle rather than the lone scholar" }, { letter: "C", text: "SO5s are anti-intellectual" }, { letter: "D", text: "SO5s are extremely extroverted" }], answer: "B", explanation: "SO5 is the counter-type Five: still knowledge-oriented but directed through group participation. They become the expert in their community, the historian in their church, the tech lead on their team, using intellectual contribution as their mode of belonging." },
  { id: 896, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Instinct x Wing Combos", question: "A Sexual (SX) Five is characterized by:", options: [{ letter: "A", text: "Fear of intimacy" }, { letter: "B", text: "Intense, idealized connections with a few chosen people, they share their secret inner world with select individuals, creating exclusive bonds of extreme depth" }, { letter: "C", text: "Casual dating" }, { letter: "D", text: "Complete isolation" }], answer: "B", explanation: "SX Fives are the most relational Five subtype. They open their guarded inner world to a chosen few, creating bonds of extraordinary intensity and depth. Their approach to relationships is all-or-nothing: complete trust or total withdrawal." },
  { id: 897, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Tritype Deep Dives", question: "The 593 tritype ('The Problem Solver') approaches challenges by:", options: [{ letter: "A", text: "Emotional processing" }, { letter: "B", text: "Combining Five's deep analysis with Nine's ability to see all perspectives and Three's drive for efficient solutions, creating a uniquely effective and unbiased problem-solver" }, { letter: "C", text: "Avoiding the problem" }, { letter: "D", text: "Delegating to others" }], answer: "B", explanation: "The 593 tritype creates a balanced problem-solver: Five provides analytical depth, Nine provides multi-perspective fairness, and Three provides results-orientation. This combination can see all sides deeply and still reach a practical outcome." },
  { id: 898, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Tritype Deep Dives", question: "The 514 tritype ('The Iconoclast') is known for:", options: [{ letter: "A", text: "Social conformity" }, { letter: "B", text: "Combining Five's intellectual rigor with One's moral conviction and Four's originality, creating a deeply principled, creative thinker who challenges conventions with both logic and passion" }, { letter: "C", text: "Following trends" }, { letter: "D", text: "Avoiding all conflict" }], answer: "B", explanation: "The 514 tritype is the intellectual rebel: Five's depth, One's principles, and Four's originality combine to create someone who challenges orthodoxy with rigorous, passionate argument. They're the type to write the book that changes a field." },
  { id: 899, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Growth Practices", question: "Why is 'sharing knowledge before feeling fully ready' a growth practice for Fives?", options: [{ letter: "A", text: "They're naturally generous with knowledge" }, { letter: "B", text: "It confronts their belief that they never know enough, and reveals that imperfect sharing still has value, breaking the preparation-forever cycle" }, { letter: "C", text: "It doesn't help them" }, { letter: "D", text: "It builds their resume" }], answer: "B", explanation: "Fives wait until they're 100% prepared to share, which means never. Sharing at 80% readiness teaches them that their imperfect contribution still has enormous value. The world needs their 80% knowledge more than it needs their eventual 100%." },
  { id: 900, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Growth Practices", question: "Physical exercise is particularly important for Fives because:", options: [{ letter: "A", text: "They need to lose weight" }, { letter: "B", text: "It moves them out of their head and into their body, reconnecting with physical sensations they've minimized and discovering that the body generates energy rather than just consuming it" }, { letter: "C", text: "It's socially expected" }, { letter: "D", text: "It improves their analytical skills" }], answer: "B", explanation: "Fives live from the neck up. Physical exercise is a corrective that says: 'You have a body. It's not just a vehicle for your brain.' The revelation that movement GENERATES energy (rather than depleting it) is transformative for a type that conserves everything." },
  { id: 901, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Naranjo's Character Types", question: "Claudio Naranjo described the Five's character as:", options: [{ letter: "A", text: "The People-Pleaser" }, { letter: "B", text: "The 'schizoid' character, not the disorder, but a personality organized around withdrawal, detachment, and the replacement of direct experience with mental representation" }, { letter: "C", text: "The Performer" }, { letter: "D", text: "The Rebel" }], answer: "B", explanation: "Naranjo borrowed the term 'schizoid' (from character analysis, not pathology) to describe the Five: someone who has substituted thinking about life for living it, mental maps for territory, and ideas about feelings for feelings themselves." },
  { id: 902, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Panel Wisdom", question: "In Enneagram panels, Type 5s commonly report:", options: [{ letter: "A", text: "Loving surprises" }, { letter: "B", text: "The painful discovery that their withdrawal strategy, designed to protect them, was also what prevented them from having the very experiences and connections they secretly wanted" }, { letter: "C", text: "Having no regrets" }, { letter: "D", text: "Being extremely social" }], answer: "B", explanation: "Five panels often feature this poignant realization: 'The walls I built to keep the world out also kept me in.' The protection that served them as children became the prison that limited their adult lives, and recognizing this is both painful and liberating." },
  { id: 903, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Differential Diagnosis", question: "How do you distinguish a Type 5 from a Type 9?", options: [{ letter: "A", text: "They're the same type" }, { letter: "B", text: "Both are withdrawn, but Fives withdraw to think and conserve energy, while Nines withdraw to avoid conflict and merge with comfortable routines, the Five's inner world is active; the Nine's inner world is numbed" }, { letter: "C", text: "Nines are smarter" }, { letter: "D", text: "Fives are more social" }], answer: "B", explanation: "Both types withdraw, but for different reasons and with different inner experiences. The Five's withdrawal is energetic and focused, their mind is highly active. The Nine's withdrawal is diffuse and numbing, they lose contact with their own desires and energy." },
  { id: 904, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Differential Diagnosis", question: "A quiet, analytical person could be a Five or a One. The differentiator is:", options: [{ letter: "A", text: "Intelligence level" }, { letter: "B", text: "Ones analyze to judge and improve; Fives analyze to understand and prepare, the One says 'this should be better,' the Five says 'let me understand how this works'" }, { letter: "C", text: "They can't be distinguished" }, { letter: "D", text: "Fives are always right" }], answer: "B", explanation: "Both types are thoughtful and precise, but their motivations differ. The One's analysis is evaluative ('Is this right?'), while the Five's is exploratory ('How does this work?'). The One wants to improve; the Five wants to comprehend." },
  { id: 905, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Workplace Archetypes", question: "A Five with a 6-wing (5w6) in the workplace tends to:", options: [{ letter: "A", text: "Be a risk-taker" }, { letter: "B", text: "Combine deep expertise with systematic thinking and loyalty to the team, they're the reliable technical anchor who foresees problems and builds robust solutions" }, { letter: "C", text: "Avoid all technical work" }, { letter: "D", text: "Seek the spotlight" }], answer: "B", explanation: "5w6 adds the Six's loyalty and systematic thinking to the Five's depth. They're the engineer who not only builds the system but also anticipates failure modes. Their work is thorough, reliable, and protective of the team's interests." },
  { id: 906, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Workplace Archetypes", question: "A Five with a 4-wing (5w4) in the workplace tends to:", options: [{ letter: "A", text: "Be a conventional corporate employee" }, { letter: "B", text: "Combine analytical depth with creative originality, they're the innovative thinker who brings unconventional, deeply researched solutions no one else would have considered" }, { letter: "C", text: "Focus only on social relationships" }, { letter: "D", text: "Avoid all intellectual work" }], answer: "B", explanation: "5w4 adds the Four's creativity and individualism to the Five's depth. They're the original thinker, not just thorough but innovative. Their solutions come from unexpected angles, drawing on both logical analysis and intuitive creativity." },
  { id: 907, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Coping Under Stress", question: "The Five's 'analysis paralysis' pattern specifically involves:", options: [{ letter: "A", text: "Not thinking enough" }, { letter: "B", text: "Gathering more and more information without ever reaching a point of 'enough', each new data point raises new questions, creating an infinite preparation loop that prevents action" }, { letter: "C", text: "Acting too quickly" }, { letter: "D", text: "Delegating all decisions" }], answer: "B", explanation: "Five analysis paralysis isn't indecision, it's infinite preparation. Each piece of knowledge reveals what they don't know yet, triggering more research. The loop is self-reinforcing: the more they know, the more they realize they don't know, and action gets permanently deferred." },
  { id: 908, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Communication Style", question: "Why do Fives often perform better in writing than in real-time conversation?", options: [{ letter: "A", text: "They have better handwriting" }, { letter: "B", text: "Writing allows them to prepare, edit, and control the output, removing the pressure of real-time emotional and social demands that drain their resources" }, { letter: "C", text: "They don't speak well" }, { letter: "D", text: "They have nothing to say in person" }], answer: "B", explanation: "Writing gives Fives what conversation doesn't: time to prepare, ability to edit, and control over the output. There's no social energy drain, no unpredictable emotional demands, and no risk of being caught without an answer. It's communication on Five terms." },
  { id: 909, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Relationship Dynamics", question: "The Five's concept of 'love by absence' means:", options: [{ letter: "A", text: "They don't love" }, { letter: "B", text: "They express love through giving space and autonomy, respecting their partner's independence the way they want their own respected, which partners from other types may misinterpret as disinterest" }, { letter: "C", text: "They love imaginary people" }, { letter: "D", text: "They only love when apart" }], answer: "B", explanation: "Fives express love by not intruding, they give partners the ultimate Five gift: undemanded space. But types that need active emotional engagement (Twos, Fours) experience this as neglect. The Five's most loving gesture can look like indifference." },
  { id: 910, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Emotional Reactions", question: "Fives often experience emotions 'after the fact' because:", options: [{ letter: "A", text: "They're delayed in everything" }, { letter: "B", text: "Their defense of isolation of affect holds feelings at bay during the event, the emotions surface later when they're alone and safe, sometimes hours or days after" }, { letter: "C", text: "They don't have emotions" }, { letter: "D", text: "They choose to feel later" }], answer: "B", explanation: "The emotional delay isn't a choice, it's the defense of isolation of affect operating automatically. During events, the Five is in data-collection mode. Later, when safe and alone, the feelings arrive, sometimes with surprising intensity." },
  // ── DIFFICULTY 4 (20 questions) ──
  { id: 911, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Ichazo Fixations", question: "Oscar Ichazo named the Five's fixation 'stinginess.' In his framework, this means:", options: [{ letter: "A", text: "Not spending money" }, { letter: "B", text: "The cognitive habit of withholding engagement from life, hoarding not just knowledge but energy, presence, and participation, as if each interaction depletes a finite and irreplaceable reservoir" }, { letter: "C", text: "Being frugal" }, { letter: "D", text: "Collecting physical objects" }], answer: "B", explanation: "Ichazo's 'stinginess' is existential withholding: the Five holds back their full presence from every encounter. They give 50% of their attention, 30% of their feelings, and keep the rest in reserve, as if life itself is a limited resource." },
  { id: 912, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Ichazo Fixations", question: "The Five's holy idea in Ichazo's system is 'Holy Omniscience' (or 'Holy Transparency'). This means:", options: [{ letter: "A", text: "They should know everything" }, { letter: "B", text: "The recognition that reality is inherently knowable through direct participation, understanding comes from engagement with life, not withdrawal from it" }, { letter: "C", text: "God knows everything" }, { letter: "D", text: "They should be transparent with others" }], answer: "B", explanation: "Holy Omniscience teaches that true knowing comes from being IN reality, not apart from it. The Five's strategy, withdrawing to understand, is precisely backward. Direct engagement IS understanding. Participation IS knowledge. You can't know the ocean from the shore." },
  { id: 913, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Object Relations Deep", question: "In object relations theory, the Five's developmental challenge relates to:", options: [{ letter: "A", text: "Excessive attachment" }, { letter: "B", text: "The 'schizoid dilemma', the fear that closeness will engulf them but distance will leave them empty, creating a perpetual oscillation between longing for and retreating from contact" }, { letter: "C", text: "Oedipal conflict" }, { letter: "D", text: "Birth trauma" }], answer: "B", explanation: "Guntrip's schizoid dilemma is the Five's core relational bind: get close and be consumed, stay distant and be empty. Neither position feels safe, creating the Five's characteristic pattern of tentative approach and sudden withdrawal." },
  { id: 914, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Object Relations Deep", question: "The Five's 'inner object' (internalized relationships) tend to be:", options: [{ letter: "A", text: "Warm and secure" }, { letter: "B", text: "Experienced as demanding and depleting, the internalized other is always needing something, which is why even imagining social contact can feel exhausting" }, { letter: "C", text: "Nonexistent" }, { letter: "D", text: "Purely positive" }], answer: "B", explanation: "The Five has internalized a demanding object: their mental representation of 'other people' is inherently needy and draining. This means even thinking about social interaction activates the defense of withdrawal, the internal other demands before the real person does." },
  { id: 915, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Counter-Instinctual Combos", question: "Why is the Social Five (SO5) considered the counter-type?", options: [{ letter: "A", text: "They're antisocial" }, { letter: "B", text: "They direct the Five's intellectual energy outward through group knowledge, becoming the expert within communities, teaching, and connecting through shared expertise, which looks un-Five-like" }, { letter: "C", text: "They're identical to other Fives" }, { letter: "D", text: "They're extremely emotional" }], answer: "B", explanation: "SO5 is counter-typical because they seek connection through intellectual contribution to groups. They're the professor, the community expert, the one who belongs through knowledge-sharing. Their avarice manifests as withholding knowledge rather than withholding presence." },
  { id: 916, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Counter-Instinctual Combos", question: "An SP5 with a 4-wing (SP 5w4) often resembles:", options: [{ letter: "A", text: "A typical extrovert" }, { letter: "B", text: "A hermit-artist, someone who creates deeply personal work in extreme isolation, with minimal need for recognition or social connection" }, { letter: "C", text: "A business executive" }, { letter: "D", text: "A party host" }], answer: "B", explanation: "SP 5w4 is perhaps the most withdrawn Enneagram combination: self-preservation withdrawal + Five's detachment + Four-wing's introspection = someone who can live happily in a cabin creating art or research that may never be seen by others." },
  { id: 917, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Historical Enneagram", question: "In Riso and Hudson's framework, the Five's 'Direction of Disintegration' at unhealthy levels manifests as:", options: [{ letter: "A", text: "Generosity" }, { letter: "B", text: "Hyperactive, scattered Seven behavior, the Five becomes manic, impulsive, and desperately seeking stimulation to escape the terror of their own inner emptiness" }, { letter: "C", text: "Increased focus" }, { letter: "D", text: "Social engagement" }], answer: "B", explanation: "At unhealthy levels, Five disintegration to Seven becomes extreme: the normally still, contained Five becomes frantically active, filling the void with consumption, substances, or chaotic activity. The mind that was too still becomes a mind that can't stop." },
  { id: 918, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Historical Enneagram", question: "The Enneagram's Head center triad (5, 6, 7) all deal with fear. The Five's specific relationship with fear is:", options: [{ letter: "A", text: "They don't experience fear" }, { letter: "B", text: "They manage fear by retreating into the mind, if they can understand and predict everything, they'll never be caught unprepared, and knowledge becomes a fortress against the threatening world" }, { letter: "C", text: "They confront fear directly" }, { letter: "D", text: "They worry about everything" }], answer: "B", explanation: "All Head types manage fear differently: Sixes scan for threats (externalize fear), Sevens plan escapes (outrun fear), Fives build knowledge fortresses (intellectualize fear). The Five says: 'If I understand it completely, it can't hurt me.'" },
  { id: 919, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Integration/Disintegration Chains", question: "When a Five integrates to Eight, the specific transformation involves:", options: [{ letter: "A", text: "Becoming a bully" }, { letter: "B", text: "Discovering that acting in the world generates energy rather than depleting it, the Five moves from the observation tower into the arena, taking up physical and emotional space they'd previously avoided" }, { letter: "C", text: "Losing their intelligence" }, { letter: "D", text: "Becoming rigid" }], answer: "B", explanation: "Eight-integration is revolutionary for Fives: they discover that engagement CREATES energy. The more they act, the more alive they feel, exactly opposite to their core belief. They become embodied, assertive, and present, thinkers who also do." },
  { id: 920, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Integration/Disintegration Chains", question: "The 5-8-2 integration/disintegration chain reveals:", options: [{ letter: "A", text: "Random connections" }, { letter: "B", text: "A journey from detached observation (5) through powerful engagement (8) to generous connection (2), the Five must first learn to act, then to give, reclaiming the very warmth they once feared would deplete them" }, { letter: "C", text: "Three unrelated types" }, { letter: "D", text: "A downward spiral" }], answer: "B", explanation: "The 5-8-2 trajectory traces the Five's complete healing: from withdrawn observation to embodied power to openhearted generosity. Each step confronts a layer of fear: acting, then connecting, then giving, the three things the Five believed would destroy them." },
  { id: 921, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Naranjo's Character Types", question: "Naranjo observed that the Five's intellectual brilliance often masks:", options: [{ letter: "A", text: "More intelligence" }, { letter: "B", text: "A profound emotional impoverishment, the mind became so developed precisely because the heart was abandoned, creating knowledge-rich but experience-poor individuals" }, { letter: "C", text: "Physical strength" }, { letter: "D", text: "Social skills" }], answer: "B", explanation: "Naranjo saw the Five's intellect as compensatory: the mind overdeveloped because the emotional and physical dimensions were underdeveloped. Brilliance is real but lopsided, like a bodybuilder who only trains one arm." },
  { id: 922, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Differential Diagnosis", question: "A person is detached, analytical, and emotionally unavailable. How do you distinguish a Five from a Three?", options: [{ letter: "A", text: "They're the same" }, { letter: "B", text: "Fives are detached because they're conserving energy and feel genuinely threatened by emotional demands; Threes are detached because emotions don't serve their image, the Five can't engage, the Three won't engage" }, { letter: "C", text: "Threes are smarter" }, { letter: "D", text: "Fives are more successful" }], answer: "B", explanation: "Both can appear emotionally distant, but the mechanism differs. The Five's detachment is protective withdrawal from overwhelming demands. The Three's detachment is strategic bypassing of emotions that don't serve achievement. One hides; the other ignores." },
  { id: 923, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Shadow Work", question: "The Five's 'emotional debt' refers to:", options: [{ letter: "A", text: "Owing money" }, { letter: "B", text: "Years of unfelt feelings accumulated in the body and unconscious, the emotions they've intellectualized rather than experienced don't disappear, they compound, and eventually demand payment" }, { letter: "C", text: "Feeling guilty about spending" }, { letter: "D", text: "Taking too many emotional risks" }], answer: "B", explanation: "Every emotion a Five converts to thought instead of feeling gets stored rather than processed. Over time, this creates a massive backlog of unfelt experience. When the dam breaks, through grief, love, or crisis, decades of emotions can arrive at once." },
  { id: 924, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Growth Practices", question: "Why is 'generous sharing without checking if the recipient is worthy' a growth practice for Fives?", options: [{ letter: "A", text: "They're naturally generous" }, { letter: "B", text: "It confronts both their knowledge-hoarding instinct and their tendency to vet people before giving, learning to give freely reveals that sharing doesn't deplete them but actually enriches the exchange" }, { letter: "C", text: "It helps them make friends" }, { letter: "D", text: "It's not a real practice" }], answer: "B", explanation: "Fives share knowledge selectively: only with people they deem worthy, only when they feel adequately prepared. Sharing freely, without gatekeeping, challenges the scarcity mindset and reveals that knowledge grows through sharing, not hoarding." },
  { id: 925, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Tritype Deep Dives", question: "The 548 tritype ('The Strategist') differs from the 549 tritype ('The Contemplative') in that:", options: [{ letter: "A", text: "They're the same" }, { letter: "B", text: "The 548 adds Eight's forcefulness and Four's emotional intensity, creating a powerful, decisive Five; the 549 adds Nine's acceptance and Four's depth, creating a more peaceful, dreamy Five" }, { letter: "C", text: "549 is more aggressive" }, { letter: "D", text: "548 is more passive" }], answer: "B", explanation: "Same core (Five) but radically different energy: 548 is the Five who acts with force, a strategic powerhouse. 549 is the Five who observes with acceptance, a peaceful sage. One is a sword; the other is a mirror." },
  { id: 926, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Spiritual Traditions", question: "The Five's relationship with mysticism is paradoxical because:", options: [{ letter: "A", text: "They're anti-spiritual" }, { letter: "B", text: "They're drawn to esoteric knowledge but resist the experiential surrender mysticism requires, they want to understand enlightenment without actually letting go of the knower" }, { letter: "C", text: "They're natural mystics" }, { letter: "D", text: "They prefer organized religion" }], answer: "B", explanation: "Fives are attracted to the knowledge-heavy aspects of mysticism, kabbalah, esoteric texts, philosophical frameworks, but resist the moment where understanding must give way to direct experience. They want the map of the territory, not the territory itself." },
  { id: 927, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Parenting Style", question: "The Five parent's greatest growth edge is:", options: [{ letter: "A", text: "Teaching more" }, { letter: "B", text: "Being physically and emotionally present without retreat, learning to tolerate the unpredictable, messy, demanding reality of a child who needs them NOW, not after they've processed" }, { letter: "C", text: "Reading more parenting books" }, { letter: "D", text: "Being stricter" }], answer: "B", explanation: "Children don't wait for the Five to process. They need hugs now, attention now, presence now. The Five parent's growth is learning that being there, fully, physically, emotionally, doesn't deplete them but actually fills both parent and child." },
  { id: 928, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Attachment Style", question: "The Five's dismissive-avoidant attachment differs from the Eight's in that:", options: [{ letter: "A", text: "They're identical" }, { letter: "B", text: "The Five avoids attachment out of scarcity fear (I don't have enough energy to connect); the Eight avoids attachment out of vulnerability fear (connecting means someone can hurt me)" }, { letter: "C", text: "Eights aren't avoidant" }, { letter: "D", text: "Fives are more connected" }], answer: "B", explanation: "Both types can be dismissive-avoidant, but the underlying fear differs. The Five says: 'If I connect, I'll be depleted.' The Eight says: 'If I connect, I'll be controlled.' Same behavioral result, different psychological engine." },
  { id: 929, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Conflict Style", question: "When a Five is in deep conflict with a partner, their most problematic pattern is:", options: [{ letter: "A", text: "Explosive anger" }, { letter: "B", text: "The 'stone wall', they become so overwhelmed by the emotional intensity that they freeze, unable to speak or respond, appearing indifferent while actually in internal crisis" }, { letter: "C", text: "Verbal aggression" }, { letter: "D", text: "People-pleasing" }], answer: "B", explanation: "Gottman's 'stonewalling' is the Five's default in emotional conflict. They're not being cold, they're flooded. The internal experience is overwhelming, but externally they freeze. Partners see indifference; the Five feels like they're drowning." },
  { id: 930, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Somatic Patterns", question: "The Five's relationship with appetite and embodiment typically manifests as:", options: [{ letter: "A", text: "Excessive indulgence" }, { letter: "B", text: "Minimal attention to physical needs, forgetting to eat, ignoring fatigue, and treating the body as an inconvenience that distracts from the mind's real work" }, { letter: "C", text: "Intense physical training" }, { letter: "D", text: "Constant snacking" }], answer: "B", explanation: "Fives can disconnect from bodily signals so thoroughly that they forget to eat, ignore pain, and push through exhaustion. The body is treated as the mind's life-support system rather than as an integral part of their experience. This physical neglect mirrors their emotional withholding." },
  // ── DIFFICULTY 5 (20 questions) ──
  { id: 931, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Ichazo Fixations", question: "Ichazo's concept of the Five's 'trap' is 'observer.' What does this mean?", options: [{ letter: "A", text: "Observation is their strength" }, { letter: "B", text: "The Five believes that observing life constitutes living it, but the observer position is itself the fixation, and stepping out of observation into participation is the actual path to the knowledge they seek" }, { letter: "C", text: "They should observe more carefully" }, { letter: "D", text: "Observation is always helpful" }], answer: "B", explanation: "The trap is the strategy that seems like growth but deepens the fixation. For Fives, becoming a better observer feels like progress but actually reinforces detachment. True knowledge, what they most desire, comes only through engaged participation, not from the sidelines." },
  { id: 932, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Ichazo Fixations", question: "The Five's virtue is 'Non-Attachment' (or 'Detachment'). This paradoxically means:", options: [{ letter: "A", text: "Being more withdrawn" }, { letter: "B", text: "Not the Five's usual detachment from life, but detachment from the NEED to detach, releasing the compulsion to withdraw, conserve, and hoard, and freely engaging because they trust that they have enough" }, { letter: "C", text: "Having no possessions" }, { letter: "D", text: "Being indifferent to everything" }], answer: "B", explanation: "The Five's virtue isn't more withdrawal, it's freedom from the compulsion to withdraw. True non-attachment means they no longer NEED to hoard time, energy, or knowledge because they trust in their essential adequacy. They can give freely because they ARE enough." },
  { id: 933, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Object Relations Deep", question: "The Five's 'in vitro' experience of life (living it in the mind rather than in reality) relates to which psychoanalytic concept?", options: [{ letter: "A", text: "Free association" }, { letter: "B", text: "Winnicott's concept of 'transitional space' gone wrong, the Five creates a mental version of reality that substitutes for actual engagement, like a transitional object that was never outgrown" }, { letter: "C", text: "The pleasure principle" }, { letter: "D", text: "The superego" }], answer: "B", explanation: "Winnicott described transitional objects as healthy bridges between inner and outer reality. The Five's mental life becomes a transitional space that never transitions, they live in the representation of reality rather than reality itself, like preferring the map to the territory forever." },
  { id: 934, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Counter-Instinctual Combos", question: "An SX5 (Sexual Five) can be confused with a Type 4 because:", options: [{ letter: "A", text: "They're the same type" }, { letter: "B", text: "The sexual instinct adds intense, idealized connection-seeking to the Five's depth, they form deep, exclusive bonds and can appear dramatically emotional within those select relationships, mimicking Four's intensity" }, { letter: "C", text: "They look like Eights" }, { letter: "D", text: "They're extroverted" }], answer: "B", explanation: "SX5 breaks the Five stereotype by forming intensely emotional bonds with chosen individuals. Within these relationships, they reveal the depth of feeling they hide from the world. This selective emotional intensity looks very Four-like, but the underlying motivation remains Five: understanding through intimate connection." },
  { id: 935, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Historical Enneagram", question: "The Enneagram of Process positions the Five between Four and Six. What does this reveal about the Five's inner world?", options: [{ letter: "A", text: "Nothing meaningful" }, { letter: "B", text: "The Five is caught between the Four's pull toward emotional depth and the Six's pull toward security, they use the mind to navigate between the danger of feeling too much and the danger of an unpredictable world" }, { letter: "C", text: "They should become a 4 or 6" }, { letter: "D", text: "It's alphabetical" }], answer: "B", explanation: "Between Four and Six, the Five navigates two threats: the Four-wing pulls toward overwhelming emotion, the Six-wing pulls toward anxious scanning for threats. The mind becomes the Five's control center, managing both emotional depth and existential fear through understanding." },
  { id: 936, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Integration/Disintegration Chains", question: "The complete Five growth trajectory (5→8→2) reveals:", options: [{ letter: "A", text: "Random type connections" }, { letter: "B", text: "A path from withdrawn observation (5) through embodied power (8) to generous giving (2), each step reclaims what the Five had disowned: first action, then connection, then openhearted generosity" }, { letter: "C", text: "A purely intellectual journey" }, { letter: "D", text: "A path to more isolation" }], answer: "B", explanation: "The 5→8→2 path is a progressive opening: from mind (Five) to body (Eight) to heart (Two). The Five reclaims their disowned centers one at a time, first action and power, then warmth and connection. The endpoint is a full human being, not just a brilliant mind." },
  { id: 937, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Naranjo's Character Types", question: "Naranjo's description of the Five's 'thinking as a replacement for living' means:", options: [{ letter: "A", text: "They think too much" }, { letter: "B", text: "The Five has constructed a complete mental simulation of life that they inhabit instead of actual reality, they think about eating instead of eating, think about love instead of loving, think about anger instead of being angry" }, { letter: "C", text: "They should stop thinking" }, { letter: "D", text: "Thinking and living are the same thing" }], answer: "B", explanation: "Naranjo's insight is that the Five doesn't just think a lot, they've replaced living with thinking. The mental simulation is so complete and detailed that the Five may not realize they're watching a movie of life rather than living it. The map has replaced the territory." },
  { id: 938, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Panel Wisdom", question: "The most common breakthrough Fives report in deep personal work is:", options: [{ letter: "A", text: "Gaining more knowledge" }, { letter: "B", text: "The discovery that they have far more energy and capacity than they believed, the 'not enough' story was a myth, and engagement generates rather than depletes their resources" }, { letter: "C", text: "Learning to withdraw more effectively" }, { letter: "D", text: "Becoming more analytical" }], answer: "B", explanation: "The Five's most transformative realization is that their scarcity belief was wrong. They actually have more energy, more emotional capacity, and more resilience than they thought. The fortress was built against a threat that was largely imaginary." },
  { id: 939, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Differential Diagnosis", question: "A person is brilliant, socially withdrawn, and has restricted emotional expression. How do you differentiate a Five from autism spectrum presentation?", options: [{ letter: "A", text: "They're the same thing" }, { letter: "B", text: "The Five's social withdrawal is a CHOICE driven by energy conservation, they CAN read social cues but choose to minimize engagement; autism involves a genuine difference in social cognition, not a strategic withdrawal" }, { letter: "C", text: "Five is just undiagnosed autism" }, { letter: "D", text: "There's no overlap" }], answer: "B", explanation: "Key distinction: Fives can read social situations accurately, they just choose not to engage. Autism involves genuine neurological differences in social perception. Fives play the social game when motivated; people with autism may genuinely struggle with it. And yes, a person can be both." },
  { id: 940, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Shadow Work", question: "The Five's ultimate shadow work involves recognizing:", options: [{ letter: "A", text: "That they need more data" }, { letter: "B", text: "That their withdrawal pattern, which felt like self-protection, was actually self-deprivation, and that the life they've been preparing to live has been passing them by while they were preparing" }, { letter: "C", text: "That emotions are irrelevant" }, { letter: "D", text: "That they're already perfect" }], answer: "B", explanation: "The Five's shattering insight: 'I was so busy preparing to live that I forgot to live.' The knowledge fortress that promised safety actually ensured impoverishment. Every relationship avoided, every experience analyzed instead of felt, every year spent preparing, all of it was life unlived." },
  { id: 941, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Growth Practices", question: "Why is 'saying yes to social invitations before thinking about it' a transformative practice for Fives?", options: [{ letter: "A", text: "It improves their calendar" }, { letter: "B", text: "It bypasses the analysis-withdrawal circuit that would normally talk them out of attending, committing before their defense system activates reveals that social engagement is rarely as draining as anticipated" }, { letter: "C", text: "It doesn't help" }, { letter: "D", text: "It makes them more popular" }], answer: "B", explanation: "The Five's withdrawal is so automatic that the 'no' happens before conscious thought. Saying yes immediately circumvents the defense system. And afterward, Fives often discover a surprising truth: it wasn't as bad as they expected, and some of it was actually energizing." },
  { id: 942, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Tritype Deep Dives", question: "The 513 tritype ('The Technical Expert') combines:", options: [{ letter: "A", text: "Three unrelated aspects" }, { letter: "B", text: "Five's depth with One's precision and Three's results-orientation, creating a highly competent, exacting professional who delivers thorough, polished, and efficient work" }, { letter: "C", text: "Maximum emotional expression" }, { letter: "D", text: "Social butterfly traits" }], answer: "B", explanation: "The 513 tritype creates the quintessential expert professional: Five's deep knowledge, One's exacting standards, and Three's drive for excellent results. This combination excels in technical fields where quality, expertise, and deliverables matter, but may be emotionally inaccessible." },
  { id: 943, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Spiritual Traditions", question: "The Five's spiritual challenge is ultimately about:", options: [{ letter: "A", text: "Learning more about spirituality" }, { letter: "B", text: "The surrender of the known, giving up the safety of intellectual understanding to enter the direct experience of mystery that no framework can contain" }, { letter: "C", text: "Joining a spiritual community" }, { letter: "D", text: "Meditating longer" }], answer: "B", explanation: "Every spiritual tradition eventually demands what the Five fears most: letting go of knowing. The mystic's 'cloud of unknowing,' Zen's 'don't-know mind,' the apophatic tradition's via negativa, all require the Five to step beyond the boundary of the thinkable into direct experience." },
  { id: 944, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Communication Style", question: "The Five's 'delayed emotional processing' creates which unique communication pattern?", options: [{ letter: "A", text: "They're always emotional" }, { letter: "B", text: "They may circle back to conversations days or weeks later with the emotional response that was missing in real-time, surprising partners who thought the topic was closed" }, { letter: "C", text: "They never process emotions" }, { letter: "D", text: "They respond instantly" }], answer: "B", explanation: "Partners of Fives learn to expect the 'emotional callback': 'Remember three weeks ago when you said...? I've been thinking about that, and I feel...' The Five's emotional processor runs on a different timeline, delivering results long after the original input." },
  { id: 945, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Instinct x Wing Combos", question: "Rank the six Five subtypes from most to least socially engaged:", options: [{ letter: "A", text: "All are the same" }, { letter: "B", text: "SO 5w6 (most engaged) → SO 5w4 → SX 5w6 → SX 5w4 → SP 5w6 → SP 5w4 (most withdrawn)" }, { letter: "C", text: "SP 5w4 is most social" }, { letter: "D", text: "Rankings don't apply" }], answer: "B", explanation: "Social instinct increases engagement; SP instinct decreases it. The 6-wing adds systematic group-oriented thinking; the 4-wing adds individualistic withdrawal. SO 5w6 is the Five most embedded in communities; SP 5w4 is the Five most comfortable in complete solitude." },
  { id: 946, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Panel Wisdom", question: "Long-time Enneagram teachers observe that Fives who have done significant growth are characterized by:", options: [{ letter: "A", text: "More knowledge" }, { letter: "B", text: "A surprising warmth and generosity, they become some of the most genuinely giving types, because their giving comes from overflow rather than obligation" }, { letter: "C", text: "Increased withdrawal" }, { letter: "D", text: "More analytical power" }], answer: "B", explanation: "The Five growth arc is perhaps the most dramatic in the Enneagram: from the most withholding to surprisingly generous. When Fives discover they have enough, their giving becomes profound, unhurried, unobliged, and genuinely free. Two-integration at its finest." },
  { id: 947, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Naranjo's Character Types", question: "Naranjo's ultimate insight about the Five's transformation is:", options: [{ letter: "A", text: "They should study more" }, { letter: "B", text: "The Five must discover that they were never actually separate from life, the withdrawal that felt like protection was itself the wound, and return to engagement IS the homecoming they've been intellectually seeking" }, { letter: "C", text: "They need better boundaries" }, { letter: "D", text: "Thinking is the highest form of being" }], answer: "B", explanation: "Naranjo's insight: the Five's separation from life wasn't a solution, it was the problem disguised as a solution. What they've been seeking through knowledge was always available through participation. The observer must become the participant to find what was never actually lost." },
  { id: 948, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Historical Enneagram", question: "The philosopher Ludwig Wittgenstein, often typed as a Five, demonstrated Five integration when he:", options: [{ letter: "A", text: "Wrote more books" }, { letter: "B", text: "Left academic philosophy to work as a gardener and elementary school teacher, moving from abstract thought to direct physical and interpersonal engagement with life" }, { letter: "C", text: "Became more isolated" }, { letter: "D", text: "Developed more complex theories" }], answer: "B", explanation: "Wittgenstein's move from Cambridge to manual labor and teaching exemplifies Five integration to Eight: leaving the mind-fortress to engage physically and relationally with ordinary life. He discovered that direct experience contained a truth that philosophy couldn't capture." },
  { id: 949, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Relationship Dynamics", question: "The Five's ultimate relational breakthrough is:", options: [{ letter: "A", text: "Finding the perfect independent relationship" }, { letter: "B", text: "Discovering that true intimacy, being fully seen, known, and present with another, doesn't deplete but nourishes, overturning the core scarcity belief that organized their entire life" }, { letter: "C", text: "Learning to need no one" }, { letter: "D", text: "Finding an equally withdrawn partner" }], answer: "B", explanation: "When a Five finally allows full intimacy, not intellectual sharing but emotional presence, they discover the foundational lie: connection generates energy. The scarcity that drove their withdrawal was itself the cause of the scarcity. Love fills rather than drains." },
  { id: 950, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Differential Diagnosis", question: "A person who says 'I need to understand everything before I can act' could be a Five or a Six. The key distinction is:", options: [{ letter: "A", text: "They're the same motivation" }, { letter: "B", text: "The Five seeks understanding as an end in itself, knowledge IS the goal; the Six seeks understanding as a means to safety, knowledge is the tool for predicting threats" }, { letter: "C", text: "Sixes don't research" }, { letter: "D", text: "Fives don't worry" }], answer: "B", explanation: "Both types research extensively before acting, but for different reasons. The Five says: 'I need to understand this because it's fascinating and I feel competent when I know.' The Six says: 'I need to understand this because I need to predict what could go wrong.' Knowledge as treasure vs. knowledge as shield." },
];
